// ===================================================
// WF-01-A: getClasses - 클래스 목록 조회
// NocoDB tbl_Classes에서 active 클래스 조회 + 필터/정렬/페이징
// ===================================================

const body = $input.first().json.body;

// 파라미터 파싱
const category = (body.category || '').trim();
const level = (body.level || '').trim();
const classType = (body.type || '').trim();
const region = (body.region || '').trim();
const sort = (body.sort || 'latest').trim();
const page = Math.max(parseInt(body.page) || 1, 1);
const limit = Math.min(Math.max(parseInt(body.limit) || 20, 1), 50);

// NocoDB where 파라미터 구성 (status=active 기본)
let whereParts = ['(status,eq,active)'];
if (category) whereParts.push(`(category,eq,${category})`);
if (level) whereParts.push(`(level,eq,${level})`);
if (classType) whereParts.push(`(type,eq,${classType})`);
if (region) whereParts.push(`(location,like,%${region}%)`);

const where = whereParts.join('~and');

// NocoDB 정렬 매핑
let sortField = '-created_date'; // 기본: 최신순 (- = DESC)
switch (sort) {
  case 'popular':   sortField = '-class_count'; break;
  case 'rating':    sortField = '-avg_rating'; break;
  case 'price_asc': sortField = 'price'; break;
  case 'price_desc':sortField = '-price'; break;
  case 'latest':
  default:          sortField = '-created_date'; break;
}

return [{
  json: {
    where,
    sortField,
    page,
    limit,
    offset: (page - 1) * limit,
    sort,
    // 원본 파라미터 보존 (응답 구성용)
    _params: { category, level, classType, region, sort, page, limit }
  }
}];

// ===================================================
// 클래스 목록 + 파트너 정보 조인 + 페이지네이션 응답 구성
// ===================================================

// NocoDB 응답에서 데이터 추출
const classesResponse = $('NocoDB Get Classes').first().json;
const partnersResponse = $('NocoDB Get Partners (Join)').first().json;
const params = $('Parse getClasses Params').first().json._params;

const classesList = classesResponse.list || [];
const partnersList = partnersResponse.list || [];

// 파트너 코드 -> 파트너 정보 맵
const partnerMap = {};
for (const p of partnersList) {
  partnerMap[p.partner_code] = {
    partner_name: p.partner_name || '',
    grade: p.grade || '',
    location: p.location || '',
    avg_rating: Number(p.avg_rating) || 0
  };
}

// 클래스 목록 구성 (파트너 이름 조인)
const classes = classesList.map(c => {
  // NocoDB Links 필드에서 partner_code 추출
  // Links 필드는 배열 형태: [{partner_code: 'PC_...'}] 또는 문자열
  let partnerCode = '';
  if (Array.isArray(c.partner_code) && c.partner_code.length > 0) {
    partnerCode = c.partner_code[0].partner_code || c.partner_code[0].Title || c.partner_code[0].Id || '';
  } else if (typeof c.partner_code === 'string') {
    partnerCode = c.partner_code;
  }

  const partnerInfo = partnerMap[partnerCode] || { partner_name: '', grade: '' };

  return {
    class_id: c.class_id || '',
    makeshop_product_id: c.makeshop_product_id || '',
    class_name: c.class_name || '',
    category: c.category || '',
    level: c.level || '',
    price: Number(c.price) || 0,
    duration_min: Number(c.duration_min) || 0,
    max_students: Number(c.max_students) || 0,
    thumbnail_url: c.thumbnail_url || '',
    location: c.location || '',
    tags: c.tags || '',
    type: c.type || '',
    class_count: Number(c.class_count) || 0,
    avg_rating: Number(c.avg_rating) || 0,
    partner_name: partnerInfo.partner_name,
    partner_code: partnerCode
  };
});

// 페이지네이션
const totalCount = classes.length;
const limit = params.limit;
const page = params.page;
const totalPages = Math.ceil(totalCount / limit);
const startIdx = (page - 1) * limit;
const pagedClasses = classes.slice(startIdx, startIdx + limit);

return [{
  json: {
    success: true,
    data: pagedClasses,
    pagination: {
      page,
      limit,
      totalCount,
      totalPages
    },
    timestamp: new Date().toISOString()
  }
}];

// ===================================================
// WF-01-B: getClassDetail 파라미터 검증
// ===================================================

const body = $input.first().json.body;
const classId = (body.id || '').trim();

if (!classId) {
  return [{
    json: {
      _error: true,
      success: false,
      error: { code: 'MISSING_PARAMS', message: 'id 파라미터가 필요합니다.' },
      timestamp: new Date().toISOString()
    }
  }];
}

return [{
  json: {
    classId,
    _error: false
  }
}];

// ===================================================
// 클래스 상세 응답 구성
// NocoDB 조회 결과 + 파트너 공개 정보 포함
// ===================================================

const response = $input.first().json;
const classesList = response.list || [];

if (classesList.length === 0) {
  return [{
    json: {
      success: false,
      error: { code: 'CLASS_NOT_FOUND', message: '해당 클래스를 찾을 수 없습니다.' },
      timestamp: new Date().toISOString()
    }
  }];
}

const c = classesList[0];

// 커리큘럼 JSON 파싱
let curriculum = [];
if (c.curriculum_json) {
  try {
    curriculum = JSON.parse(c.curriculum_json);
  } catch (e) {
    // 파싱 실패 시 빈 배열
  }
}

// 이미지 URL 배열 변환 (콤마 구분)
let images = [];
if (c.image_urls) {
  images = c.image_urls.split(',').map(u => u.trim()).filter(u => u.length > 0);
}

// 일정 JSON 파싱
let schedules = [];
if (c.schedules_json) {
  try {
    const parsed = JSON.parse(c.schedules_json);
    if (Array.isArray(parsed)) schedules = parsed;
  } catch (e) {}
}

// 재료 상품 ID 배열
let materialsProductIds = [];
if (c.materials_product_ids) {
  materialsProductIds = c.materials_product_ids.split(',').map(id => id.trim()).filter(id => id.length > 0);
}

// partner_code 추출 (Links 필드 또는 문자열)
let partnerCode = '';
if (Array.isArray(c.partner_code) && c.partner_code.length > 0) {
  partnerCode = c.partner_code[0].partner_code || c.partner_code[0].Title || '';
} else if (typeof c.partner_code === 'string') {
  partnerCode = c.partner_code;
}

return [{
  json: {
    _classData: {
      class_id: c.class_id || '',
      makeshop_product_id: c.makeshop_product_id || '',
      class_name: c.class_name || '',
      category: c.category || '',
      level: c.level || '',
      price: Number(c.price) || 0,
      materials_price: Number(c.materials_price) || 0,
      duration_min: Number(c.duration_min) || 0,
      max_students: Number(c.max_students) || 0,
      description: c.description || '',
      curriculum,
      instructor_bio: c.instructor_bio || '',
      thumbnail_url: c.thumbnail_url || '',
      images,
      youtube_video_id: c.youtube_video_id || '',
      location: c.location || '',
      materials_included: c.materials_included || '',
      materials_product_ids: materialsProductIds,
      tags: c.tags || '',
      type: c.type || '',
      class_count: Number(c.class_count) || 0,
      avg_rating: Number(c.avg_rating) || 0,
      schedules
    },
    _partnerCode: partnerCode,
    _needPartner: true
  }
}];

// ===================================================
// 클래스 상세 + 파트너 + 일정 정보 결합 -> 최종 응답
// ===================================================

const classResponse = $('NocoDB Get Class Detail').first().json;
const classesList = classResponse.list || [];

if (classesList.length === 0) {
  return [{ json: { success: false, error: { code: 'CLASS_NOT_FOUND', message: '해당 클래스를 찾을 수 없습니다.' }, timestamp: new Date().toISOString() } }];
}

const c = classesList[0];

let curriculum = [];
try { if (c.curriculum_json) curriculum = JSON.parse(c.curriculum_json); } catch(e) {}

let images = [];
if (c.image_urls) images = c.image_urls.split(',').map(u => u.trim()).filter(u => u.length > 0);

let materialsProductIds = [];
if (c.materials_product_ids) materialsProductIds = c.materials_product_ids.split(',').map(id => id.trim()).filter(id => id.length > 0);

// tbl_Schedules 기반 일정 (schedules_json 대신)
const schedulesResponse = $input.first().json;
const schedulesList = schedulesResponse.list || [];
const schedules = schedulesList.map(s => ({
  schedule_id: s.schedule_id,
  schedule_date: s.schedule_date,
  schedule_time: s.schedule_time,
  capacity: s.capacity || 8,
  booked_count: s.booked_count || 0,
  remaining: (s.capacity || 8) - (s.booked_count || 0)
}));

// 파트너 정보
const partnerResponse = $('NocoDB Get Partner (Detail)').first().json;
const partnerList = partnerResponse.list || [];
let partner = { partner_code: '', partner_name: '', grade: '', location: '', avg_rating: 0, instagram_url: '', portfolio_url: '' };
if (partnerList.length > 0) {
  const p = partnerList[0];
  partner = { partner_code: p.partner_code || '', partner_name: p.partner_name || '', grade: p.grade || '', location: p.location || '', avg_rating: Number(p.avg_rating) || 0, instagram_url: p.instagram_url || '', portfolio_url: p.portfolio_url || '' };
}

return [{ json: {
  success: true,
  data: {
    class_id: c.class_id || '', makeshop_product_id: c.makeshop_product_id || '',
    class_name: c.class_name || '', category: c.category || '', level: c.level || '',
    price: Number(c.price) || 0, materials_price: Number(c.materials_price) || 0,
    duration_min: Number(c.duration_min) || 0, max_students: Number(c.max_students) || 0,
    description: c.description || '', curriculum, instructor_bio: c.instructor_bio || '',
    thumbnail_url: c.thumbnail_url || '', images, youtube_video_id: c.youtube_video_id || '',
    location: c.location || '', materials_included: c.materials_included || '',
    materials_product_ids: materialsProductIds, tags: c.tags || '', type: c.type || '',
    class_count: Number(c.class_count) || 0, avg_rating: Number(c.avg_rating) || 0,
    schedules, partner
  },
  timestamp: new Date().toISOString()
} }];

// ===================================================
// WF-01-C: getCategories - 카테고리 목록 + 건수 집계
// active 클래스에서 카테고리별 건수를 집계합니다.
// ===================================================

const response = $input.first().json;
const classesList = response.list || [];

// 카테고리별 건수 집계
const categories = {};
for (const c of classesList) {
  const cat = (c.category || '').trim();
  if (cat) {
    categories[cat] = (categories[cat] || 0) + 1;
  }
}

// 배열로 변환 + 건수 내림차순 정렬
const categoryList = Object.entries(categories)
  .map(([name, classCount]) => ({ name, class_count: classCount }))
  .sort((a, b) => b.class_count - a.class_count);

return [{
  json: {
    success: true,
    data: categoryList,
    timestamp: new Date().toISOString()
  }
}];

// ===================================================
// Fallback: 알 수 없는 action 에러 응답
// ===================================================

const action = ($input.first().json.body || {}).action || '';

return [{
  json: {
    success: false,
    error: {
      code: 'INVALID_ACTION',
      message: `알 수 없는 요청입니다: ${action}`
    },
    timestamp: new Date().toISOString()
  }
}];
